// Extract and clean documentation content
const html = $input.item.json.data;

// Remove script tags, style tags, navigation, and other non-content elements
const cleanHtml = html
  .replace(/<script[^>]*>.*?<\/script>/gis, '')
  .replace(/<style[^>]*>.*?<\/style>/gis, '')
  .replace(/<nav[^>]*>.*?<\/nav>/gis, '')
  .replace(/<header[^>]*>.*?<\/header>/gis, '')
  .replace(/<footer[^>]*>.*?<\/footer>/gis, '');

// Extract text content, code blocks, and headings
const textContent = cleanHtml
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// Extract code blocks with language hints
const codeBlockRegex = /<pre[^>]*><code[^>]*class=["']language-(\w+)["'][^>]*>(.*?)<\/code><\/pre>/gis;
const codeBlocks = [];
let match;

while ((match = codeBlockRegex.exec(html)) !== null) {
  codeBlocks.push({
    language: match[1],
    code: match[2].replace(/<[^>]+>/g, '').trim()
  });
}

// Extract headings for structure
const headingRegex = /<h([1-6])[^>]*>(.*?)<\/h[1-6]>/gi;
const headings = [];

while ((match = headingRegex.exec(html)) !== null) {
  headings.push({
    level: parseInt(match[1]),
    text: match[2].replace(/<[^>]+>/g, '').trim()
  });
}

return {
  json: {
    documentationUrl: $input.item.json.url || $json.body.documentationUrl,
    textContent: textContent.substring(0, 8000), // Limit for AI processing
    codeBlocks: codeBlocks,
    headings: headings,
    rawHtml: html.substring(0, 5000) // Keep sample for reference
  }
};

// Parse AI response and validate structure
const aiResponse = $input.item.json.response || $input.item.json.content?.[0]?.text;

if (!aiResponse) {
  throw new Error('No AI response received');
}

// Remove markdown code fences if present
const cleanedResponse = aiResponse
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

let tutorialOutline;
try {
  tutorialOutline = JSON.parse(cleanedResponse);
} catch (error) {
  throw new Error(`Failed to parse AI response: ${error.message}`);
}

// Validate required fields
if (!tutorialOutline.sections || !Array.isArray(tutorialOutline.sections)) {
  throw new Error('Invalid tutorial outline: missing sections array');
}

// Add metadata
tutorialOutline.createdAt = new Date().toISOString();
tutorialOutline.sourceUrl = $('Parse Documentation Content').item.json.documentationUrl;
tutorialOutline.totalSections = tutorialOutline.sections.length;

// Calculate total estimated duration
const totalSeconds = tutorialOutline.sections.reduce((sum, section) => {
  return sum + (parseInt(section.duration) || 30);
}, 0);
tutorialOutline.totalDurationSeconds = totalSeconds;
tutorialOutline.totalDurationMinutes = Math.ceil(totalSeconds / 60);

return {
  json: tutorialOutline
};

// Generate narration audio script with timing markers
const outline = $input.item.json;
const sections = outline.sections;

const narrationScript = sections.map((section, index) => {
  const timestamp = sections.slice(0, index).reduce((sum, s) => sum + parseInt(s.duration || 30), 0);

  return {
    sectionIndex: index,
    sectionTitle: section.sectionTitle,
    startTime: timestamp,
    duration: parseInt(section.duration || 30),
    narrationText: section.narration,
    voiceSettings: {
      speed: 1.0,
      pitch: 1.0,
      voice: 'en-US-Neural2-J' // Male voice for tech tutorials
    }
  };
});

// Create intro narration
const intro = {
  sectionIndex: -1,
  sectionTitle: 'Introduction',
  startTime: 0,
  duration: 10,
  narrationText: `Welcome to this tutorial on ${outline.videoTitle}. ${outline.videoDescription}`,
  voiceSettings: {
    speed: 1.0,
    pitch: 1.0,
    voice: 'en-US-Neural2-J'
  }
};

// Create outro narration
const outro = {
  sectionIndex: 999,
  sectionTitle: 'Conclusion',
  startTime: outline.totalDurationSeconds,
  duration: 8,
  narrationText: 'Thank you for watching this tutorial. Don\'t forget to subscribe for more developer content, and check the description for links and resources.',
  voiceSettings: {
    speed: 1.0,
    pitch: 1.0,
    voice: 'en-US-Neural2-J'
  }
};

return {
  json: {
    videoTitle: outline.videoTitle,
    narrationSegments: [intro, ...narrationScript, outro],
    totalSegments: narrationScript.length + 2
  }
};

// Create visual scene instructions for video generation
const outline = $('Structure Tutorial Outline').item.json;
const sections = outline.sections;

const videoScenes = sections.map((section, index) => {
  const scene = {
    sceneIndex: index,
    sectionTitle: section.sectionTitle,
    duration: parseInt(section.duration || 30),
    visualType: section.visualType,
    transitions: {
      in: 'fade',
      out: 'fade'
    }
  };

  // Configure scene based on visual type
  switch (section.visualType) {
    case 'code':
      scene.content = {
        type: 'code-editor',
        code: section.codeSnippet || section.terminalCommands?.join('\n') || '',
        language: detectLanguage(section.codeSnippet || ''),
        theme: 'dracula',
        highlightLines: [],
        typewriterEffect: true,
        typeSpeed: 50 // milliseconds per character
      };
      break;

    case 'terminal':
      scene.content = {
        type: 'terminal',
        commands: section.terminalCommands || [],
        prompt: '$ ',
        theme: 'dark',
        typeSpeed: 80
      };
      break;

    case 'diagram':
      scene.content = {
        type: 'diagram',
        diagramType: 'flowchart',
        elements: section.keyPoints || [],
        animation: 'progressive-reveal'
      };
      break;

    case 'screen':
      scene.content = {
        type: 'screen-recording',
        overlayText: section.keyPoints || [],
        highlights: true
      };
      break;

    default:
      scene.content = {
        type: 'text-overlay',
        title: section.sectionTitle,
        bullets: section.keyPoints || []
      };
  }

  return scene;
});

function detectLanguage(code) {
  if (code.includes('function') || code.includes('const') || code.includes('let')) return 'javascript';
  if (code.includes('def ') || code.includes('import ')) return 'python';
  if (code.includes('<?php')) return 'php';
  if (code.includes('public class')) return 'java';
  return 'plaintext';
}

return {
  json: {
    videoTitle: outline.videoTitle,
    totalDuration: outline.totalDurationSeconds + 18, // Including intro/outro
    scenes: videoScenes,
    resolution: '1920x1080',
    fps: 30,
    codec: 'h264'
  }
};

// Compile final response with video details
const outline = $('Structure Tutorial Outline').item.json;
const youtubeData = $('Upload to YouTube').item.json;
const driveData = $('Backup to Google Drive').item.json;

const response = {
  success: true,
  message: 'Tutorial video created successfully',
  video: {
    title: outline.videoTitle,
    duration: `${outline.totalDurationMinutes} minutes`,
    sections: outline.totalSections,
    sourceUrl: outline.sourceUrl,
    createdAt: outline.createdAt
  },
  youtube: {
    videoId: youtubeData.id || 'pending',
    url: youtubeData.id ? `https://youtube.com/watch?v=${youtubeData.id}` : 'pending',
    status: youtubeData.status || 'uploaded'
  },
  backup: {
    driveId: driveData.id || '',
    driveUrl: driveData.webViewLink || ''
  },
  metadata: {
    prerequisites: outline.prerequisites || [],
    learningOutcomes: outline.learningOutcomes || []
  }
};

return {
  json: response
};
